import React from 'react';
import type { Song } from '../types';
import { motion } from 'framer-motion';

interface SongSelectorProps {
  songs: Song[];
  selectedSong: Song;
  onSelectSong: (song: Song) => void;
}

export const SongSelector: React.FC<SongSelectorProps> = ({ songs, selectedSong, onSelectSong }) => {
  return (
    <ul className="flex flex-col space-y-1">
      {songs.map((song, index) => {
        const isSelected = selectedSong.id === song.id;
        return (
          <li key={song.id}>
            <motion.button
              whileHover={{ x: 4 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => onSelectSong(song)}
              className={`w-full text-left p-3 rounded-xl transition-all duration-300 flex items-center space-x-3 border ${
                isSelected
                  ? 'bg-gradient-to-r from-amber-500/10 to-transparent border-amber-500/30 shadow-[inset_2px_0_0_0_rgba(245,158,11,1)]'
                  : 'bg-transparent border-transparent hover:bg-white/5 text-stone-500 hover:text-stone-300'
              }`}
            >
              <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold font-mono transition-colors ${
                  isSelected ? 'bg-amber-500 text-stone-900' : 'bg-stone-800 text-stone-600'
              }`}>
                  {index + 1}
              </div>

              <div className="flex flex-col min-w-0">
                  <span className={`font-semibold truncate transition-colors ${isSelected ? 'text-stone-100' : ''}`}>
                    {song.name}
                  </span>
                  {isSelected && (
                      <span className="text-[10px] text-amber-500/80 uppercase tracking-wider font-medium">Tocando agora</span>
                  )}
              </div>
            </motion.button>
          </li>
        );
      })}
    </ul>
  );
};

import React from 'react';
import type { TrackState } from '../types';
import { motion } from 'framer-motion';

interface TrackControlProps {
  trackState: TrackState;
  setVolume: (trackId: number, volume: number) => void;
  toggleMute: (trackId: number) => void;
  toggleSolo: (trackId: number) => void;
  errorMessage?: string;
}

const ErrorIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" {...props}>
        <path fillRule="evenodd" d="M8.485 2.495c.673-1.167 2.357-1.167 3.03 0l6.28 10.875c.673 1.167-.17 2.625-1.516 2.625H3.72c-1.347 0-2.189-1.458-1.515-2.625L8.485 2.495zM10 5a.75.75 0 01.75.75v3.5a.75.75 0 01-1.5 0v-3.5A.75.75 0 0110 5zm0 9a1 1 0 100-2 1 1 0 000 2z" clipRule="evenodd" />
    </svg>
);

export const TrackControl: React.FC<TrackControlProps> = ({ trackState, setVolume, toggleMute, toggleSolo, errorMessage }) => {
  const { id, instrument, volume, isMuted, isSoloed } = trackState;
  const hasError = !!errorMessage;

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setVolume(id, parseFloat(e.target.value));
  };

  const MAX_VOLUME = 1.2;
  const volumeDb = volume === 0 ? -Infinity : 20 * Math.log10(volume);
  const displayDb = isFinite(volumeDb) ? volumeDb.toFixed(1) : '-INF';
  const faderFillPercentage = Math.min((volume / MAX_VOLUME) * 100, 100);

  // Determine colors based on volume level (Green -> Amber -> Red zone)
  const getFaderColor = (vol: number) => {
      if (vol > 1.0) return 'bg-gradient-to-t from-orange-500 to-red-500';
      if (vol > 0.8) return 'bg-gradient-to-t from-amber-500 to-orange-500';
      return 'bg-gradient-to-t from-lime-600 to-amber-500';
  };

  return (
    <motion.div 
        layout
        className={`flex flex-col items-center p-3 bg-[#131110] rounded-2xl w-28 h-full border border-white/5 shadow-xl relative overflow-hidden group`}
    >
      {/* Background texture for the "channel strip" */}
      <div className="absolute inset-0 bg-stone-800/20 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none"></div>

      {/* Instrument Name */}
      <div className="text-center w-full mb-3 relative z-10">
        <div className="flex items-center justify-center space-x-1 h-6">
            {hasError ? (
                <div title={errorMessage}>
                    <ErrorIcon className="w-4 h-4 text-red-500" />
                </div>
            ) : (
                 <div className="w-1.5 h-1.5 rounded-full bg-emerald-500/50 shadow-[0_0_5px_rgba(16,185,129,0.5)]"></div>
            )}
        </div>
        <p className="text-xs font-bold uppercase tracking-wider text-stone-400 truncate w-full" title={instrument}>
            {instrument}
        </p>
      </div>

      {/* Mute/Solo Buttons */}
      <div className="flex flex-col space-y-2 mb-4 w-full px-1 z-10">
        <motion.button
          whileTap={{ scale: 0.95 }}
          onClick={() => toggleSolo(id)}
          className={`w-full py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-widest border transition-all duration-200 ${
            isSoloed 
                ? 'bg-amber-500 text-stone-900 border-amber-400 shadow-[0_0_15px_rgba(245,158,11,0.4)]' 
                : 'bg-stone-800/50 text-stone-500 border-stone-700 hover:bg-stone-700 hover:text-stone-300'
          }`}
          disabled={hasError}
        >
          Solo
        </motion.button>
        <motion.button
          whileTap={{ scale: 0.95 }}
          onClick={() => toggleMute(id)}
          className={`w-full py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-widest border transition-all duration-200 ${
            isMuted 
                ? 'bg-red-500/90 text-white border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.4)]' 
                : 'bg-stone-800/50 text-stone-500 border-stone-700 hover:bg-stone-700 hover:text-stone-300'
          }`}
          disabled={hasError}
        >
          Mute
        </motion.button>
      </div>

      {/* Fader Track */}
      <div className="flex-grow relative w-12 flex justify-center z-10">
         {/* The groove */}
        <div className="relative h-full w-2 bg-black/60 rounded-full shadow-[inset_0_0_4px_rgba(0,0,0,0.8)] border border-white/5 overflow-hidden">
             {/* The filled level */}
            <motion.div 
                className={`absolute bottom-0 left-0 right-0 w-full ${getFaderColor(volume)} opacity-80`}
                style={{ height: `${faderFillPercentage}%` }}
                layoutId={`fader-fill-${id}`}
                transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            />
        </div>

        {/* 0dB Marker */}
        <div className="absolute right-0 left-0 top-[16.6%] border-t border-white/10 opacity-50 text-[9px] text-stone-600 text-right pr-4 pointer-events-none">
            0
        </div>

        {/* The Input (Overlay) */}
        <input
            type="range"
            min="0"
            max={MAX_VOLUME}
            step="0.01"
            value={volume}
            onChange={handleVolumeChange}
            className="appearance-none [writing-mode:vertical-lr] bg-transparent w-8 h-full cursor-pointer absolute inset-0 z-20 opacity-0"
            disabled={hasError}
            title={`${instrument} Volume: ${displayDb}dB`}
        />

        {/* The Visual Thumb Handle (Follows value) */}
        <motion.div 
            className="absolute left-1/2 -ml-4 w-8 h-5 bg-gradient-to-b from-stone-600 to-stone-800 rounded shadow-lg border-t border-white/20 border-b border-black/50 pointer-events-none z-10 flex items-center justify-center"
            style={{ bottom: `calc(${faderFillPercentage}% - 10px)` }}
        >
            <div className="w-6 h-[1px] bg-stone-900 shadow-[0_1px_0_rgba(255,255,255,0.1)]"></div>
        </motion.div>
      </div>

      {/* Volume Readout */}
      <div className="mt-3 w-full text-center">
         <div className="bg-black/40 rounded px-1 py-0.5 border border-white/5 shadow-inner">
            <p className={`text-[10px] font-mono font-bold ${isMuted ? 'text-stone-600' : (volume > 1.0 ? 'text-red-400' : 'text-amber-500')}`}>
                {hasError ? 'ERR' : `${displayDb}`}
            </p>
         </div>
      </div>
    </motion.div>
  );
};

import React from 'react';
import { motion } from 'framer-motion';

interface TransportControlsProps {
  isPlaying: boolean;
  onPlay: () => void;
  onPause: () => void;
  onStop: () => void;
  onReturnToZero: () => void;
  hasErrors: boolean;
  currentTime: number;
  songDuration: number;
  onSeek: (time: number) => void;
}

const PlayIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
    <path fillRule="evenodd" d="M4.5 5.653c0-1.426 1.529-2.33 2.779-1.643l11.54 6.647c1.295.742 1.295 2.545 0 3.286L7.279 20.99c-1.25.717-2.779-.217-2.779-1.643V5.653z" clipRule="evenodd" />
  </svg>
);

const PauseIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
    <path fillRule="evenodd" d="M6.75 5.25a.75.75 0 01.75.75v12a.75.75 0 01-1.5 0V6a.75.75 0 01.75-.75zm9 0a.75.75 0 01.75.75v12a.75.75 0 01-1.5 0V6a.75.75 0 01.75-.75z" clipRule="evenodd" />
  </svg>
);

const StopIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
    <path fillRule="evenodd" d="M4.5 7.5a3 3 0 013-3h9a3 3 0 013 3v9a3 3 0 01-3 3h-9a3 3 0 01-3-3v-9z" clipRule="evenodd" />
  </svg>
);

const RewindIcon: React.FC<React.SVGProps<SVGSVGElement>> = (props) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" {...props}>
        <path fillRule="evenodd" d="M9.53 2.47a.75.75 0 010 1.06L4.81 8.25H15a6.75 6.75 0 010 13.5h-3a.75.75 0 010-1.5h3a5.25 5.25 0 100-10.5H4.81l4.72 4.72a.75.75 0 11-1.06 1.06l-6-6a.75.75 0 010-1.06l6-6a.75.75 0 011.06 0z" clipRule="evenodd" />
    </svg>
);

const formatTime = (timeInSeconds: number): string => {
    if (isNaN(timeInSeconds) || timeInSeconds < 0) {
        return '00:00';
    }
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = Math.floor(timeInSeconds % 60);
    return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
};

export const TransportControls: React.FC<TransportControlsProps> = ({ isPlaying, onPlay, onPause, onStop, onReturnToZero, hasErrors, currentTime, songDuration, onSeek }) => {
  const progressPercent = songDuration > 0 ? (currentTime / songDuration) * 100 : 0;

  return (
    <div className="flex flex-col items-center justify-center space-y-2 w-full max-w-lg">
      <div className="flex items-center space-x-6">
        <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={onReturnToZero} 
          className="text-stone-500 hover:text-stone-300 transition-colors p-2" 
          title="Início"
        >
          <RewindIcon className="w-5 h-5" />
        </motion.button>

        {isPlaying ? (
            <motion.button 
                whileHover={{ scale: 1.1, boxShadow: "0 0 20px rgba(245, 158, 11, 0.4)" }}
                whileTap={{ scale: 0.95 }}
                onClick={onPause}
                className="p-3 rounded-full bg-gradient-to-br from-amber-400 to-amber-600 text-stone-900 shadow-lg shadow-amber-900/40 border border-amber-300/20"
                aria-label="Pause"
            >
                <PauseIcon className="w-8 h-8" />
            </motion.button>
        ) : (
            <motion.button 
                whileHover={!hasErrors ? { scale: 1.1, boxShadow: "0 0 20px rgba(245, 158, 11, 0.4)" } : {}}
                whileTap={!hasErrors ? { scale: 0.95 } : {}}
                onClick={onPlay}
                className={`p-3 rounded-full shadow-lg border border-amber-300/20 ${
                    hasErrors 
                    ? 'bg-stone-800 text-stone-600 cursor-not-allowed' 
                    : 'bg-gradient-to-br from-amber-400 to-amber-600 text-stone-900 shadow-amber-900/40'
                }`}
                disabled={hasErrors}
                aria-label="Play"
            >
                <PlayIcon className="w-8 h-8 ml-0.5" />
            </motion.button>
        )}

        <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={onStop} 
          className="text-stone-500 hover:text-stone-300 transition-colors p-2" 
          title="Parar"
        >
          <StopIcon className="w-5 h-5" />
        </motion.button>
      </div>

       <div className="w-full flex items-center gap-3">
        <span className="font-mono text-[10px] text-stone-500 w-8 text-right">{formatTime(currentTime)}</span>

        <div className="relative flex-grow h-6 flex items-center group">
            <div className="absolute w-full h-1.5 bg-stone-800 rounded-full overflow-hidden">
                <motion.div 
                    className="h-full bg-amber-500/80"
                    style={{ width: `${progressPercent}%` }}
                    layoutId="progressbar"
                />
            </div>
             <input
                type="range"
                min="0"
                max={songDuration || 1}
                step="0.1"
                value={currentTime}
                onChange={(e) => onSeek(parseFloat(e.target.value))}
                className="w-full h-6 opacity-0 cursor-pointer absolute z-10"
                disabled={hasErrors || songDuration === 0}
            />
            {/* Visual thumb for hover effect */}
            <div 
                className="absolute h-3 w-3 bg-stone-200 rounded-full shadow-md pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity"
                style={{ left: `calc(${progressPercent}% - 6px)` }}
            ></div>
        </div>

        <span className="font-mono text-[10px] text-stone-500 w-8">{formatTime(songDuration)}</span>
      </div>
    </div>
  );
};

